export interface ApiMembership {
  id: string;
  referenceType: string;
  referenceId: string;
  role: string;
  member: {
    id: string;
    displayName: string;
    email: string;
    type: string;
  };
}

export function isValidApiMembership(membership: ApiMembership): boolean {
  return (
    membership != null &&
    membership.id != null &&
    membership.referenceType != null &&
    membership.referenceId != null &&
    membership.role != null &&
    membership.member != null &&
    membership.member.id != null &&
    membership.member.displayName != null
  );
}
